import React, { useEffect, useState } from 'react';
import { toast } from 'react-toastify';
import { teacherAPI } from '../services/api';

const initialForm = {
  teacherId: '',
  name: '',
  email: '',
  department: '',
  phone: '',
  isAvailable: true,
};

const Teachers = () => {
  const [teachers, setTeachers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [formData, setFormData] = useState(initialForm);

  const fetchTeachers = async () => {
    try {
      setLoading(true);
      const response = await teacherAPI.getAll();
      setTeachers(response.data || []);
    } catch (error) {
      toast.error('Failed to load teachers');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchTeachers();
  }, []);

  const onChange = (event) => {
    const { name, value, type, checked } = event.target;
    setFormData((prev) => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value,
    }));
  };

  const handleAddTeacher = async (event) => {
    event.preventDefault();
    try {
      setSubmitting(true);
      await teacherAPI.add(formData);
      toast.success('Teacher added successfully');
      setFormData(initialForm);
      fetchTeachers();
    } catch (error) {
      toast.error(error.response?.data?.error || 'Failed to add teacher');
    } finally {
      setSubmitting(false);
    }
  };

  const handleDeleteTeacher = async (teacherId) => {
    try {
      await teacherAPI.delete(teacherId);
      toast.success('Teacher deleted');
      fetchTeachers();
    } catch (error) {
      toast.error('Failed to delete teacher');
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-lg shadow-md p-6">
        <h1 className="text-3xl font-bold text-gray-800 mb-2">Teachers</h1>
        <p className="text-gray-600">Manage invigilator pool and availability.</p>
      </div>

      <div className="bg-white rounded-lg shadow-md p-6">
        <h2 className="text-xl font-semibold text-gray-800 mb-4">Add Teacher</h2>
        <form onSubmit={handleAddTeacher} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          <input
            className="input-field"
            name="teacherId"
            placeholder="Teacher ID"
            value={formData.teacherId}
            onChange={onChange}
            required
          />
          <input
            className="input-field"
            name="name"
            placeholder="Full Name"
            value={formData.name}
            onChange={onChange}
            required
          />
          <input
            className="input-field"
            type="email"
            name="email"
            placeholder="Email"
            value={formData.email}
            onChange={onChange}
            required
          />
          <input
            className="input-field"
            name="department"
            placeholder="Department"
            value={formData.department}
            onChange={onChange}
            required
          />
          <input
            className="input-field"
            name="phone"
            placeholder="Phone Number"
            value={formData.phone}
            onChange={onChange}
          />
          <label className="flex items-center space-x-2">
            <input
              type="checkbox"
              name="isAvailable"
              checked={formData.isAvailable}
              onChange={onChange}
            />
            <span className="text-gray-700">Available for invigilation</span>
          </label>
          <div className="md:col-span-2 lg:col-span-3">
            <button type="submit" className="btn-primary" disabled={submitting}>
              {submitting ? 'Adding...' : 'Add Teacher'}
            </button>
          </div>
        </form>
      </div>

      <div className="bg-white rounded-lg shadow-md p-6 overflow-x-auto">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-xl font-semibold text-gray-800">Teacher List</h2>
          <button onClick={fetchTeachers} className="btn-secondary">
            Refresh
          </button>
        </div>

        {loading ? (
          <p className="text-gray-500">Loading teachers...</p>
        ) : teachers.length === 0 ? (
          <p className="text-gray-500">No teachers added yet.</p>
        ) : (
          <table className="min-w-full">
            <thead>
              <tr className="table-header">
                <th className="px-4 py-3 text-left">ID</th>
                <th className="px-4 py-3 text-left">Name</th>
                <th className="px-4 py-3 text-left">Department</th>
                <th className="px-4 py-3 text-left">Contact</th>
                <th className="px-4 py-3 text-left">Status</th>
                <th className="px-4 py-3 text-left">Actions</th>
              </tr>
            </thead>
            <tbody>
              {teachers.map((teacher) => (
                <tr key={teacher.teacherId} className="table-row">
                  <td className="px-4 py-3 font-semibold">{teacher.teacherId}</td>
                  <td className="px-4 py-3">{teacher.name}</td>
                  <td className="px-4 py-3">{teacher.department}</td>
                  <td className="px-4 py-3">
                    <p>{teacher.email}</p>
                    <p className="text-sm text-gray-500">{teacher.phone || '-'}</p>
                  </td>
                  <td className="px-4 py-3">
                    <span className={teacher.isAvailable ? 'text-green-600' : 'text-red-600'}>
                      {teacher.isAvailable ? 'Available' : 'Unavailable'}
                    </span>
                  </td>
                  <td className="px-4 py-3">
                    <button
                      onClick={() => handleDeleteTeacher(teacher.teacherId)}
                      className="btn-danger"
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default Teachers;
